    public function parse_market(array $market): array {
        //
        //     {
        //       "name" => "BTC-USD",
        //       "uiName" => "BTC-USD",
        //       "category" => "Crypto",
        //       "subCategory" => "L1",
        //       "assetName" => "BTC",
        //       "assetPrecision" => 5,
        //       "collateralAssetName" => "USD",
        //       "collateralAssetPrecision" => 6,
        //       "description" => "Bitcoin",
        //       "active" => true,
        //       "status" => "ACTIVE",
        //       "marketStats" => array( ... ),
        //       "tradingConfig" => {
        //         "minOrderSize" => "0.0001",
        //         "minOrderSizeChange" => "0.00001",
        //         "minPriceChange" => "1",
        //         "maxMarketOrderValue" => "3000000",
        //         "maxLimitOrderValue" => "15000000",
        //         "maxPositionValue" => "60000000",
        //         "maxLeverage" => "50.00",
        //         "hourlyFundingRateCap" => "0.25",
        //         "maxNumOrders" => "200",
        //         "limitPriceCap" => "0.05",
        //         "limitPriceFloor" => "0.05",
        //         "riskFactorConfig" => array(
        //           array(
        //             "upperBound" => "4000000",
        //             "riskFactor" => "0.02",
        //             "isAvailableForUsers" => true
        //           }
        //         )
        //       ),
        //       "l2Config" => array( ... ),
        //       "visibleOnUi" => true,
        //       "createdAt" => 1752829532673
        //     }
        //
        $tradingConfig = $this->safe_dict($market, 'tradingConfig', array());
        $marketId = $this->safe_string($market, 'name');
        $baseId = $this->safe_string($market, 'assetName');
        if (mb_strpos($baseId, 'SPOT') !== false) {
            $baseId = str_replace('SPOT', '', $baseId);
        }
        $quoteId = $this->safe_string($market, 'collateralAssetName');
        $base = $this->safe_currency_code($baseId);
        $quote = $this->safe_currency_code($quoteId);
        if ($quoteId === 'USD') {
            $quote = 'USDC';
        }
        $status = $this->safe_string($market, 'status');
        $active = ($status === 'ACTIVE');
        $amountPrecision = $this->safe_number($tradingConfig, 'minOrderSizeChange');
        $pricePrecision = $this->safe_number($tradingConfig, 'minPriceChange');
        $maxLeverage = $this->safe_number($tradingConfig, 'maxLeverage');
        $minAmount = $this->safe_number($tradingConfig, 'minOrderSize');
        $maxCost = $this->safe_number($tradingConfig, 'maxLimitOrderValue');
        $created = $this->safe_integer($market, 'createdAt');
        $settleId = null;
        $settle = null;
        $symbol = $base . '/' . $quote;
        $isSpot = false;
        $type = $this->safe_string_lower($market, 'type');
        $contractSize = null;
        $linear = null;
        $inverse = null;
        if ($type === 'spot') {
            $isSpot = true;
        } else {
            $type = 'swap';
            $settleId = $quoteId;
            $settle = $quote;
            $symbol .= ':' . $settle;
            $contractSize = $this->parse_number('1');
            $linear = true;
            $inverse = false;
        }
        return $this->safe_market_structure(array(
            'id' => $marketId,
            'symbol' => $symbol,
            'base' => $base,
            'quote' => $quote,
            'settle' => $settle,
            'baseId' => $baseId,
            'quoteId' => $quoteId,
            'settleId' => $settleId,
            'type' => $type,
            'spot' => $isSpot,
            'margin' => false,
            'swap' => !$isSpot,
            'future' => false,
            'option' => false,
            'active' => $active,
            'contract' => !$isSpot,
            'linear' => $linear,
            'inverse' => $inverse,
            'taker' => $this->safe_number($this->fees, 'taker'),
            'maker' => $this->safe_number($this->fees, 'maker'),
            'contractSize' => $contractSize,
            'expiry' => null,
            'expiryDatetime' => null,
            'strike' => null,
            'optionType' => null,
            'precision' => array(
                'amount' => $amountPrecision,
                'price' => $pricePrecision,
            ),
            'limits' => array(
                'leverage' => array(
                    'min' => $this->parse_number('1'),
                    'max' => $maxLeverage,
                ),
                'amount' => array(
                    'min' => $minAmount,
                    'max' => null,
                ),
                'price' => array(
                    'min' => null,
                    'max' => null,
                ),
                'cost' => array(
                    'min' => null,
                    'max' => $maxCost,
                ),
            ),
            'created' => $created,
            'info' => $market,
        ));
    }

