    public function parse_currency(array $currency): array {
        //
        //     {
        //       "id" => 1,
        //       "name" => "USD",
        //       "symbol" => "USD",
        //       "description" => "USD Collateral",
        //       "precision" => 6,
        //       "isActive" => true,
        //       "isCollateral" => true,
        //       "starkexId" => "0x1",
        //       "starkexResolution" => 1000000,
        //       "l1Id" => "0xa0b86991c6218b36c1d19d4a2e9eb0ce3606eb48",
        //       "l1Resolution" => 1000000,
        //       "version" => 3,
        //       "createdAt" => 1752829532673,
        //       "type" => "SPOT",
        //       "canBeUsedAsCollateral" => true,
        //       "riskFactors" => array(),
        //       "availableForTradeFactors" => array()
        //     }
        //
        $currencyId = $this->safe_string($currency, 'symbol');
        if (($currencyId !== null) && (mb_strpos($currencyId, 'SPOT') !== false)) {
            $currencyId = str_replace('SPOT', '', $currencyId);
        }
        $code = $this->safe_currency_code($currencyId);
        if ($currencyId === 'USD') {
            $code = 'USDC';
        }
        $name = $this->safe_string($currency, 'name');
        $precision = $this->safe_integer($currency, 'precision');
        $isActive = $this->safe_bool($currency, 'isActive');
        return $this->safe_currency_structure(array(
            'id' => $currencyId,
            'code' => $code,
            'numericId' => $this->safe_integer($currency, 'id'),
            'name' => $name,
            'active' => $isActive,
            'deposit' => true,
            'withdraw' => true,
            'precision' => pow(10, $precision * -1),
            'type' => 'other',
            'margin' => $this->safe_bool($currency, 'canBeUsedAsCollateral'),
            'info' => $currency,
        ));
    }

