    public function fetch_tickers(?array $symbols = null, $params = array ()): array {
        /**
         * fetches price $tickers for multiple markets, statistical information calculated over the past 24 hours for all markets
         *
         * @see https://api.docs.extended.exchange/#get-markets
         *
         * @param {string[]} [$symbols] unified $symbols of the markets to fetch the $ticker for, all $market $tickers are returned if not assigned
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} a dictionary of ~@link https://docs.ccxt.com/?id=$ticker-structure $ticker structures~
         */
        $this->load_markets();
        $symbols = $this->market_symbols($symbols);
        $request = array();
        if ($symbols !== null) {
            $marketIds = array();
            for ($i = 0; $i < count($symbols); $i++) {
                $market = $this->market($symbols[$i]);
                $marketIds[] = $market['id'];
            }
            $request['market'] = $marketIds;
        }
        $response = $this->v1PublicGetInfoMarkets ($this->extend($request, $params));
        //
        //     {
        //       "status" => "OK",
        //       "data" => array(
        //         {
        //           "name" => "BTC-USD",
        //           "assetName" => "BTC",
        //           "collateralAssetName" => "USD",
        //           "marketStats" => array(
        //             "dailyVolume" => "231016077.512960",
        //             ...
        //           ),
        //           ...
        //         }
        //       )
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        $tickers = array();
        for ($i = 0; $i < count($data); $i++) {
            $marketData = $data[$i];
            $marketId = $this->safe_string($marketData, 'name');
            $market = $this->safe_market($marketId);
            $stats = $this->safe_dict($marketData, 'marketStats', array());
            $ticker = $this->parse_ticker($stats, $market);
            $symbol = $ticker['symbol'];
            $tickers[$symbol] = $ticker;
        }
        return $this->filter_by_array_tickers($tickers, 'symbol', $symbols);
    }

    public function parse_ticker($ticker, $market = null): array {
        //
        //     {
        //       "dailyVolume" => "231216165.666600",
        //       "dailyVolumeBase" => "3027.36710",
        //       "dailyPriceChange" => "181",
        //       "dailyPriceChangePercentage" => "0.0024",
        //       "dailyLow" => "75635",
        //       "dailyHigh" => "77399",
        //       "lastPrice" => "77026",
        //       "askPrice" => "77026",
        //       "bidPrice" => "77025",
        //       "markPrice" => "77006.091897999984",
        //       "indexPrice" => "77050.739529925005",
        //       "fundingRate" => "0.000012",
        //       "nextFundingRate" => 1777446000000,
        //       "openInterest" => "114851569.088316",
        //       "openInterestBase" => "1491.33012",
        //       "deleverageLevels" => {
        //         "shortPositions" => array(
        //           array( "level" => 1, "rankingLowerBound" => "-784.2884" ),
        //           array( "level" => 2, "rankingLowerBound" => "-2.1078" ),
        //           array( "level" => 3, "rankingLowerBound" => "-0.8754" ),
        //           array( "level" => 4, "rankingLowerBound" => "0.0000" )
        //         ),
        //         "longPositions" => array(
        //           array( "level" => 1, "rankingLowerBound" => "-47747.2010" ),
        //           array( "level" => 2, "rankingLowerBound" => "-0.0131" ),
        //           array( "level" => 3, "rankingLowerBound" => "0.0019" ),
        //           array( "level" => 4, "rankingLowerBound" => "0.0032" )
        //         )
        //       }
        //     }
        //
        $symbol = $this->safe_symbol(null, $market);
        $last = $this->safe_number($ticker, 'lastPrice');
        $percentageRaw = $this->safe_string($ticker, 'dailyPriceChangePercentage');
        $percentage = ($percentageRaw !== null) ? Precise::string_mul($percentageRaw, '100') : null;
        return $this->safe_ticker(array(
            'symbol' => $symbol,
            'timestamp' => null,
            'datetime' => null,
            'high' => $this->safe_number($ticker, 'dailyHigh'),
            'low' => $this->safe_number($ticker, 'dailyLow'),
            'bid' => $this->safe_number($ticker, 'bidPrice'),
            'bidVolume' => null,
            'ask' => $this->safe_number($ticker, 'askPrice'),
            'askVolume' => null,
            'vwap' => null,
            'open' => null,
            'close' => $last,
            'last' => $last,
            'previousClose' => null,
            'change' => $this->safe_number($ticker, 'dailyPriceChange'),
            'percentage' => $percentage,
            'average' => null,
            'baseVolume' => $this->safe_number($ticker, 'dailyVolumeBase'),
            'quoteVolume' => $this->safe_number($ticker, 'dailyVolume'),
            'markPrice' => $this->safe_number($ticker, 'markPrice'),
            'indexPrice' => $this->safe_number($ticker, 'indexPrice'),
            'info' => $ticker,
        ), $market);
    }

    public function fetch_order_book(string $symbol, ?int $limit = null, $params = array ()): array {
        /**
         * fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other $data
         *
         * @see https://api.docs.extended.exchange/#get-$market-order-book
         *
         * @param {string} $symbol unified $symbol of the $market to fetch the order book for
         * @param {int} [$limit] the maximum amount of order book entries to return
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @return {array} A dictionary of ~@link https://docs.ccxt.com/?id=order-book-structure order book structures~ indexed by $market symbols
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'market' => $market['id'],
        );
        $response = $this->v1PublicGetInfoMarketsMarketOrderbook ($this->extend($request, $params));
        //
        //     {
        //       "status" => "OK",
        //       "data" => {
        //         "market" => "BTC-USD",
        //         "bid" => array(
        //           {
        //             "qty" => "14.46084",
        //             "price" => "76214"
        //           }
        //         ),
        //         "ask" => array(
        //           {
        //             "qty" => "0.11585",
        //             "price" => "76215"
        //           }
        //         )
        //       }
        //     }
        //
        $data = $this->safe_dict($response, 'data', array());
        $timestamp = $this->milliseconds();
        $orderbook = $this->parse_order_book($data, $market['symbol'], $timestamp, 'bid', 'ask', 'price', 'qty');
        if ($limit !== null) {
            $orderbook['bids'] = $this->array_slice($orderbook['bids'], 0, $limit);
            $orderbook['asks'] = $this->array_slice($orderbook['asks'], 0, $limit);
        }
        return $orderbook;
    }

