    public function fetch_my_trades(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetch all trades made by the user
         *
         * @see https://api.docs.extended.exchange/#get-trades
         *
         * @param {string} [$symbol] unified $market $symbol of the trades
         * @param {int} [$since] the earliest time in ms to fetch trades for
         * @param {int} [$limit] the maximum number of trade structures to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#$pagination-$params)
         * @return {Trade[]} a list of ~@link https://docs.ccxt.com/?id=trade-structure trade structures~
         */
        $this->load_markets();
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchMyTrades', 'paginate');
        if ($paginate) {
            return $this->fetch_paginated_call_cursor('fetchMyTrades', $symbol, $since, $limit, $params, 'cursor', 'cursor', null, 100);
        }
        $market = null;
        $request = array();
        if ($symbol !== null) {
            $market = $this->market($symbol);
            $request['market'] = $market['id'];
        }
        if ($limit !== null) {
            $request['limit'] = $limit;
        }
        $response = $this->v1PrivateGetUserTrades ($this->extend($params, $request));
        //
        //     {
        //         "status" => "OK",
        //         "data" => array(
        //             {
        //                 "id" => 1,
        //                 "orderId" => 1784980437895231232,
        //                 "externalId" => "ExtId-1",
        //                 "accountId" => 1,
        //                 "market" => "BTC-USD",
        //                 "side" => "BUY",
        //                 "price" => "39000",
        //                 "qty" => "0.2",
        //                 "value" => "7800",
        //                 "fee" => "1.3",
        //                 "tradeType" => "TRADE",
        //                 "isTaker" => true,
        //                 "createdTime" => 1701563440000
        //             }
        //         ),
        //         "pagination" => {
        //             "cursor" => 1784963886257016832,
        //             "count" => 1
        //         }
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        $pagination = $this->safe_dict($response, 'pagination', array());
        $cursor = $this->safe_string($pagination, 'cursor');
        $result = array();
        $dataLength = count($data);
        for ($i = 0; $i < $dataLength; $i++) {
            $entry = $data[$i];
            if (($cursor !== null) && ($i === $dataLength - 1)) {
                $entry = $this->extend($entry, array( 'cursor' => $cursor ));
            }
            $result[] = $entry;
        }
        return $this->parse_trades($result, $market, $since, $limit);
    }

