    public function parse_funding_history($history, ?array $market = null) {
        //
        //     {
        //         "id" => 8341,
        //         "accountId" => 3137,
        //         "market" => "BNB-USD",
        //         "positionId" => 1821237954501148672,
        //         "side" => "LONG",
        //         "size" => "1.116",
        //         "value" => "560.77401888",
        //         "markPrice" => "502.48568",
        //         "fundingFee" => "0",
        //         "fundingRate" => "0",
        //         "paidTime" => 1723147241346
        //     }
        //
        $marketId = $this->safe_string($history, 'market');
        $market = $this->safe_market($marketId, $market);
        $timestamp = $this->safe_integer($history, 'paidTime');
        return array(
            'info' => $history,
            'symbol' => $market['symbol'],
            'code' => $market['settle'],
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'id' => $this->safe_string($history, 'id'),
            'amount' => $this->safe_number($history, 'fundingFee'),
            'rate' => $this->safe_number($history, 'fundingRate'),
        );
    }

    public function parse_funding_histories($histories, ?array $market = null, ?int $since = null, ?int $limit = null): array {
        $result = array();
        for ($i = 0; $i < count($histories); $i++) {
            $result[] = $this->parse_funding_history($histories[$i], $market);
        }
        $symbol = ($market === null) ? null : $market['symbol'];
        return $this->filter_by_symbol_since_limit($result, $symbol, $since, $limit);
    }

    public function parse_trade($trade, $market = null): array {
        //
        // fetchTrades
        //
        //     {
        //       "i" => 2.049676905958871e+18,
        //       "m" => "BTC-USD",
        //       "S" => "SELL",
        //       "tT" => "TRADE",
        //       "T" => 1777516030193,
        //       "p" => "76140",
        //       "q" => "0.00165"
        //     }
        //
        // fetchMyTrades
        //
        //     {
        //         "id" => 1,
        //         "orderId" => 1784980437895231232,
        //         "externalId" => "ExtId-1",
        //         "accountId" => 1,
        //         "market" => "BTC-USD",
        //         "side" => "BUY",
        //         "price" => "39000",
        //         "qty" => "0.2",
        //         "value" => "7800",
        //         "fee" => "1.3",
        //         "tradeType" => "TRADE",
        //         "isTaker" => true,
        //         "createdTime" => 1701563440000
        //     }
        //
        $marketId = $this->safe_string_2($trade, 'm', 'market');
        $market = $this->safe_market($marketId, $market);
        $timestamp = $this->safe_integer_2($trade, 'T', 'createdTime');
        $priceString = $this->safe_string_2($trade, 'p', 'price');
        $amountString = $this->safe_string_2($trade, 'q', 'qty');
        $sideRaw = $this->safe_string_2($trade, 'S', 'side');
        $side = ($sideRaw !== null) ? strtolower($sideRaw) : null;
        $feeCost = $this->safe_string($trade, 'fee');
        $fee = ($feeCost === null) ? null : array(
            'cost' => $feeCost,
            'currency' => ($market === null) ? null : $market['settle'],
        );
        $isTaker = $this->safe_bool($trade, 'isTaker');
        $takerOrMaker = null;
        if ($isTaker !== null) {
            $takerOrMaker = $isTaker ? 'taker' : 'maker';
        }
        return $this->safe_trade(array(
            'id' => $this->safe_string_2($trade, 'i', 'id'),
            'info' => $trade,
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'symbol' => $market['symbol'],
            'order' => $this->safe_string($trade, 'orderId'),
            'type' => null,
            'side' => $side,
            'takerOrMaker' => $takerOrMaker,
            'price' => $priceString,
            'amount' => $amountString,
            'cost' => $this->safe_string($trade, 'value'),
            'fee' => $fee,
        ), $market);
    }

    public function fetch_ohlcv(string $symbol, string $timeframe = '1m', ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetches historical candlestick $data containing the open, high, low, and close $price, and the volume of a $market
         *
         * @see https://api.docs.extended.exchange/#get-candles-history
         *
         * @param {string} $symbol unified $symbol of the $market to fetch OHLCV $data for
         * @param {string} $timeframe the length of time each candle represents
         * @param {int} [$since] timestamp in ms of the earliest candle to fetch
         * @param {int} [$limit] the maximum amount of candles to fetch, default 100
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->candleType] candle type => 'trades' (default), 'mark-prices', or 'index-prices'
         * @param {string} [$params->price] *ignored if $params->candleType is set* 'mark' or 'index' for mark $price and index $price candles
         * @param {int} [$params->until] end timestamp in ms for the requested period
         * @return {int[][]} A list of candles ordered, open, high, low, close, volume
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $price = $this->safe_string($params, 'price');
        $candleType = $this->safe_string($params, 'candleType');
        if ($candleType === null) {
            if ($price === 'mark') {
                $candleType = 'mark-prices';
            } elseif ($price === 'index') {
                $candleType = 'index-prices';
            } else {
                $candleType = 'trades';
            }
        }
        $until = $this->safe_integer($params, 'until');
        $params = $this->omit($params, array( 'candleType', 'price', 'until' ));
        $request = array(
            'market' => $market['id'],
            'candleType' => $candleType,
            'interval' => $this->safe_string($this->timeframes, $timeframe, $timeframe),
            'limit' => ($limit !== null) ? $limit : 100,
        );
        if ($until !== null) {
            $request['endTime'] = $until;
        }
        $response = $this->v1PublicGetInfoCandlesMarketCandleType ($this->extend($request, $params));
        //
        //     {
        //       "status" => "OK",
        //       "data" => array(
        //         {
        //           "o" => "75657.5",
        //           "l" => "75657.5",
        //           "h" => "75657.5",
        //           "c" => "75657.5",
        //           "v" => "0",
        //           "T" => 1777517880000
        //         }
        //       )
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        return $this->parse_ohlcvs($data, $market, $timeframe, $since, $limit);
    }

    public function parse_ohlcv($ohlcv, $market = null): array {
        //
