            $type = ($accountIndex === 0) ? 'main' : 'subaccount';
        }
        return array(
            'id' => $this->safe_string_2($account, 'accountId', 'id'),
            'type' => $type,
            'code' => null,
            'info' => $account,
        );
    }

    public function fetch_ledger(?string $code = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetch the history of changes, actions done by the user or operations that altered the balance of the user
         *
         * @see https://api.docs.extended.exchange/#get-deposits-withdrawals-transfers-history
         *
         * @param {string} [$code] unified $currency $code
         * @param {int} [$since] timestamp in ms of the earliest ledger $entry
         * @param {int} [$limit] max number of ledger entries to return
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#$pagination-$params)
         * @return {array[]} a list of ~@link https://docs.ccxt.com/?id=ledger ledger structures~
         */
        $this->load_markets();
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchLedger', 'paginate');
        if ($paginate) {
            return $this->fetch_paginated_call_cursor('fetchLedger', $code, $since, $limit, $params, 'cursor', 'cursor', null, 50);
        }
        $currency = null;
        if ($code !== null) {
            $currency = $this->currency($code);
        }
        $request = array();
        if ($limit !== null) {
            $request['limit'] = $limit;
        }
        $response = $this->v1PrivateGetUserAssetOperations ($this->extend($request, $params));
        $data = $this->safe_list($response, 'data', array());
        $pagination = $this->safe_dict($response, 'pagination', array());
        $cursor = $this->safe_string($pagination, 'cursor');
        $result = array();
        $dataLength = count($data);
        for ($i = 0; $i < $dataLength; $i++) {
            $entry = $data[$i];
            if (($cursor !== null) && ($i === $dataLength - 1)) {
                $entry = $this->extend($entry, array( 'cursor' => $cursor ));
            }
            $result[] = $entry;
        }
        return $this->parse_ledger($result, $currency, $since, $limit);
    }

    public function parse_ledger_entry(array $item, ?array $currency = null): array {
        //
        //     {
        //         "id" => "1951255127004282880",
        //         "type" => "TRANSFER",
        //         "status" => "COMPLETED",
        //         "amount" => "-3.0000000000000000",
        //         "fee" => "0",
        //         "asset" => 1,
        //         "time" => 1754050449502,
        //         "accountId" => 100009,
        //         "counterpartyAccountId" => 100023
        //     }
        //
        $timestamp = $this->safe_integer($item, 'time');
        $assetId = $this->safe_string($item, 'asset');
        $code = $this->get_extended_currency_code_by_id($assetId, $currency);
        $ledgerCurrency = $this->safe_currency($code, $currency);
        $amountString = $this->safe_string($item, 'amount');
        $direction = null;
        if ($amountString !== null) {
            $direction = Precise::string_lt($amountString, '0') ? 'out' : 'in';
        }
        $fee = null;
        $feeCost = $this->safe_string($item, 'fee');
        if ($feeCost !== null) {
            $fee = array(
                'currency' => $code,
                'cost' => $this->parse_number(Precise::string_abs($feeCost)),
            );
        }
        return $this->safe_ledger_entry(array(
            'info' => $item,
            'id' => $this->safe_string($item, 'id'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'direction' => $direction,
            'account' => $this->safe_string($item, 'accountId'),
            'referenceId' => $this->safe_string($item, 'transactionHash'),
            'referenceAccount' => $this->safe_string($item, 'counterpartyAccountId'),
            'type' => $this->parse_transaction_type($this->safe_string($item, 'type')),
            'currency' => $code,
            'amount' => ($amountString === null) ? null : $this->parse_number(Precise::string_abs($amountString)),
            'before' => null,
            'after' => null,
            'status' => $this->parse_transaction_status($this->safe_string($item, 'status')),
            'fee' => $fee,
        ), $ledgerCurrency);
    }

