    public function withdraw(string $code, float $amount, string $address, ?string $tag = null, $params = array ()): array {
        /**
         * make a Starknet withdrawal
         *
         * @see https://api.docs.extended.exchange/#withdrawals
         *
         * @param {string} $code unified $currency $code
         * @param {float} $amount the $amount to withdraw
         * @param {string} $address the Starknet $address to withdraw to
         * @param {string} $tag unused
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->chainId] only STRK is supported
         * @param {int} [$params->settlementExpiration] $settlement expiration timestamp in seconds, defaults to $now + 14 days + 60 seconds
         * @return {array} a ~@link https://docs.ccxt.com/?id=transaction-structure transaction structure~
         */
        $this->check_required_credentials();
        $this->load_markets();
        $currency = $this->currency($code);
        $chainId = $this->safe_string_upper_2($params, 'chainId', 'network', 'STRK');
        if ($chainId !== 'STRK') {
            throw new BadRequest($this->id . ' withdraw() only supports Starknet withdrawals with $chainId STRK');
        }
        if (strlen($address) <= 42) {
            throw new BadRequest($this->id . ' withdraw() requires a Starknet $address for STRK withdrawals, EVM withdrawals require the bridge quote flow');
        }
        $account = $this->fetch_extended_account();
        $amountString = $this->currency_to_precision($code, $amount);
        $accountId = $this->safe_string($account, 'accountId');
        $settlement = $this->create_withdrawal_settlement_data($address, $amountString, $currency, $account, $params);
        $request = array(
            'accountId' => $accountId,
            'amount' => $amountString,
            'chainId' => $chainId,
            'asset' => $currency['id'],
            'settlement' => $settlement,
        );
        $params = $this->omit($params, array( 'chainId', 'network', 'settlementExpiration', 'nonce', 'recipient', 'positionId', 'l2Vault', 'collateralId', 'resolution' ));
        $response = $this->v1PrivatePostUserWithdrawal ($this->extend($request, $params));
        //
        //     {
        //         "status" => "OK",
        //         "data" => 1820796462590083072
        //     }
        //
        $now = $this->milliseconds();
        return array(
            'info' => $response,
            'id' => $this->safe_string($response, 'data'),
            'txid' => null,
            'timestamp' => $now,
            'datetime' => $this->iso8601($now),
            'address' => $address,
            'addressFrom' => null,
            'addressTo' => $address,
            'tag' => $tag,
            'tagFrom' => null,
            'tagTo' => $tag,
            'type' => 'withdrawal',
            'amount' => $this->parse_number($amountString),
            'currency' => $currency['code'],
            'status' => 'pending',
            'updated' => $now,
            'fee' => null,
            'network' => $chainId,
            'comment' => null,
            'internal' => false,
        );
    }

    public function fetch_transfers(?string $code = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetch a history of internal transfers made on an account
         *
         * @see https://api.docs.extended.exchange/#get-deposits-withdrawals-transfers-history
         *
         * @param {string} [$code] unified $currency $code
         * @param {int} [$since] the earliest time in ms to fetch transfers for
         * @param {int} [$limit] the maximum number of transfer structures to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#$pagination-$params)
         * @return {TransferEntry[]} a list of ~@link https://docs.ccxt.com/?id=transfer-structure transfer structures~
         */
        $this->load_markets();
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchTransfers', 'paginate');
        if ($paginate) {
            return $this->fetch_paginated_call_cursor('fetchTransfers', $code, $since, $limit, $params, 'cursor', 'cursor', null, 50);
        }
        $currency = null;
        if ($code !== null) {
            $currency = $this->currency($code);
        }
        $request = array(
            'type' => 'TRANSFER',
        );
        if ($limit !== null) {
            $request['limit'] = $limit;
        }
        $response = $this->v1PrivateGetUserAssetOperations ($this->extend($request, $params));
        $data = $this->safe_list($response, 'data', array());
        $pagination = $this->safe_dict($response, 'pagination', array());
        $cursor = $this->safe_string($pagination, 'cursor');
        $result = array();
        $dataLength = count($data);
        for ($i = 0; $i < $dataLength; $i++) {
            $entry = $data[$i];
            if (($cursor !== null) && ($i === $dataLength - 1)) {
                $entry = $this->extend($entry, array( 'cursor' => $cursor ));
            }
            $result[] = $entry;
        }
        return $this->parse_transfers($result, $currency, $since, $limit);
    }

    public function transfer(string $code, float $amount, string $fromAccount, string $toAccount, $params = array ()): array {
        /**
         * transfer collateral between sub-accounts associated with the same wallet
         *
         * @see https://api.docs.extended.exchange/#create-transfer
         *
         * @param {string} $code unified $currency $code
         * @param {float} $amount the $amount to transfer
         * @param {string} $fromAccount source $account id, defaults to the authenticated $account id
         * @param {string} $toAccount destination $account id
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} $params->toVault destination $account L2 vault
         * @param {string} $params->toL2Key destination $account L2 public key
         * @param {int} [$params->settlementExpiration] $settlement expiration timestamp in seconds, defaults to $now + 21 days
         * @return {array} a ~@link https://docs.ccxt.com/?id=transfer-structure transfer structure~
         */
        $this->check_required_credentials();
        $this->load_markets();
        $currency = $this->currency($code);
        $account = $this->fetch_extended_account();
        $currentAccountId = $this->safe_string($account, 'accountId');
        if ($fromAccount === null) {
            $fromAccount = $currentAccountId;
        } elseif ($fromAccount !== $currentAccountId) {
            throw new BadRequest($this->id . ' transfer() can only transfer from the authenticated account');
        }
        $toVault = $this->safe_string_2($params, 'toVault', 'receiverPositionId');
        $toL2Key = $this->safe_string_2($params, 'toL2Key', 'receiverPublicKey');
        if (($toAccount === null) || ($toVault === null) || ($toL2Key === null)) {
            throw new ArgumentsRequired($this->id . ' transfer() requires a $toAccount argument and $params["toVault"] and $params["toL2Key"]');
        }
        $amountString = $this->currency_to_precision($code, $amount);
        $settlement = $this->create_transfer_settlement_data($amountString, $currency, $account, $toVault, $toL2Key, $params);
        $request = array(
            'fromAccount' => $fromAccount,
            'toAccount' => $toAccount,
            'amount' => $amountString,
            'transferredAsset' => $currency['id'],
            'settlement' => $settlement,
        );
        $params = $this->omit($params, array( 'fromVault', 'senderPositionId', 'fromL2Key', 'senderPublicKey', 'toVault', 'receiverPositionId', 'toL2Key', 'receiverPublicKey', 'settlementExpiration', 'nonce', 'assetId', 'collateralId', 'resolution' ));
        $response = $this->v1PrivatePostUserTransfer ($this->extend($request, $params));
        //
        //     {
        //         "status" => "OK",
        //         "data" => {
        //             "validSignature" => true,
        //             "id" => 1820778187672010752
        //         }
        //     }
        //
        $data = $this->safe_dict($response, 'data', array());
        $validSignature = $this->safe_bool($data, 'validSignature');
        $now = $this->milliseconds();
        $status = 'pending';
        if ($validSignature !== null) {
            $status = $validSignature ? 'ok' : 'failed';
        }
        return array(
            'info' => $response,
            'id' => $this->safe_string($data, 'id'),
            'timestamp' => $now,
            'datetime' => $this->iso8601($now),
            'currency' => $currency['code'],
            'amount' => $this->parse_number($amountString),
            'fromAccount' => $fromAccount,
            'toAccount' => $toAccount,
            'status' => $status,
        );
    }

    public function parse_transfer(array $transfer, ?array $currency = null): array {
        $timestamp = $this->safe_integer($transfer, 'time');
        $assetId = $this->safe_string($transfer, 'asset');
        $code = $this->get_extended_currency_code_by_id($assetId, $currency);
        $amountString = $this->safe_string($transfer, 'amount');
        $amount = ($amountString === null) ? null : $this->parse_number(Precise::string_abs($amountString));
        $accountId = $this->safe_string($transfer, 'accountId');
        $counterpartyAccountId = $this->safe_string($transfer, 'counterpartyAccountId');
        $fromAccount = $accountId;
        $toAccount = $counterpartyAccountId;
        if (($amountString !== null) && !Precise::string_lt($amountString, '0')) {
            $fromAccount = $counterpartyAccountId;
            $toAccount = $accountId;
        }
        $validSignature = $this->safe_bool($transfer, 'validSignature');
        $status = null;
        if ($validSignature !== null) {
            $status = $validSignature ? 'ok' : 'failed';
        } else {
            $status = $this->parse_transaction_status($this->safe_string($transfer, 'status'));
        }
        return array(
            'info' => $transfer,
            'id' => $this->safe_string($transfer, 'id'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'currency' => $code,
            'amount' => $amount,
            'fromAccount' => $fromAccount,
            'toAccount' => $toAccount,
            'status' => $status,
        );
    }

    public function get_extended_currency_code_by_id(?string $assetId, ?array $currency = null): ?string {
        if ($assetId === null) {
            return $this->safe_string($currency, 'code');
        }
        $currenciesByNumericId = $this->safe_dict($this->options, 'currenciesByNumericId', array());
        $currencyByNumericId = $this->safe_dict($currenciesByNumericId, $assetId);
        if ($currencyByNumericId !== null) {
            return $this->safe_string($currencyByNumericId, 'code');
        }
        if ($currency !== null) {
            return $currency['code'];
        }
        $code = $this->safe_currency_code($assetId);
        if ($code === 'USD') {
            $code = 'USDC';
        }
        return $code;
    }

    public function parse_transaction_status(?string $status): ?string {
        $statuses = array(
            'CREATED' => 'pending',
            'IN_PROGRESS' => 'pending',
            'COMPLETED' => 'ok',
            'REJECTED' => 'failed',
        );
        return $this->safe_string($statuses, $status, $status);
    }

    public function parse_transaction_type(?string $type): ?string {
        $types = array(
            'DEPOSIT' => 'deposit',
            'WITHDRAWAL' => 'withdrawal',
            'TRANSFER' => 'transfer',
            'CLAIM' => 'claim',
        );
        return $this->safe_string($types, $type, $type);
    }

    public function parse_transaction(array $transaction, ?array $currency = null): array {
        //
        //     {
        //         "id" => "1951255127004282880",
        //         "type" => "TRANSFER",
        //         "status" => "COMPLETED",
        //         "amount" => "-3.0000000000000000",
        //         "fee" => "0",
        //         "asset" => 1,
        //         "time" => 1754050449502,
        //         "accountId" => 100009,
        //         "counterpartyAccountId" => 100023
        //     }
        //
        $timestamp = $this->safe_integer($transaction, 'time');
        $assetId = $this->safe_string($transaction, 'asset');
        $code = $this->get_extended_currency_code_by_id($assetId, $currency);
        $amountString = $this->safe_string($transaction, 'amount');
        $amount = ($amountString === null) ? null : $this->parse_number(Precise::string_abs($amountString));
        $fee = null;
        $feeCost = $this->safe_string($transaction, 'fee');
        if ($feeCost !== null) {
            $fee = array(
                'currency' => $code,
                'cost' => $this->parse_number(Precise::string_abs($feeCost)),
            );
        }
        $transactionType = $this->parse_transaction_type($this->safe_string($transaction, 'type'));
        $network = $this->safe_string($transaction, 'chain');
        return array(
            'info' => $transaction,
            'id' => $this->safe_string($transaction, 'id'),
            'txid' => $this->safe_string($transaction, 'transactionHash'),
            'timestamp' => $timestamp,
            'datetime' => $this->iso8601($timestamp),
            'address' => null,
            'addressFrom' => null,
            'addressTo' => null,
            'tag' => null,
            'tagFrom' => null,
            'tagTo' => null,
            'type' => $transactionType,
            'amount' => $amount,
            'currency' => $code,
            'status' => $this->parse_transaction_status($this->safe_string($transaction, 'status')),
            'updated' => $timestamp,
            'fee' => $fee,
            'network' => $network,
            'comment' => null,
            'internal' => ($transactionType === 'transfer'),
        );
    }

    public function fetch_trading_fee(string $symbol, $params = array ()): array {
        /**
