         * @see https://api.docs.extended.exchange/#get-fees
         *
         * @param {string} $symbol unified $market $symbol
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->builderId] builder client id
         * @return {array} a ~@link https://docs.ccxt.com/?id=fee-structure fee structure~
         */
        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'market' => $market['id'],
        );
        $response = $this->v1PrivateGetUserFees ($this->extend($request, $params));
        //
        //     {
        //         "status" => "OK",
        //         "data" => array(
        //             {
        //                 "market" => "BTC-USD",
        //                 "makerFeeRate" => "0.00000",
        //                 "takerFeeRate" => "0.00025",
        //                 "builderFeeRate" => "0.0001"
        //             }
        //         )
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        $first = $this->safe_dict($data, 0, array());
        return $this->parse_trading_fee($first, $market);
    }

    public function fetch_trading_fees($params = array ()): array {
        /**
         * fetch the trading fees for multiple markets
         *
         * @see https://api.docs.extended.exchange/#get-fees
         *
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {string} [$params->market] exchange market id
         * @param {string} [$params->builderId] builder client id
         * @return {array} a dictionary of ~@link https://docs.ccxt.com/?id=$fee-structure $fee structures~ indexed by market symbols
         */
        $this->load_markets();
        $response = $this->v1PrivateGetUserFees ($params);
        //
        //     {
        //         "status" => "OK",
        //         "data" => array(
        //             {
        //                 "market" => "BTC-USD",
        //                 "makerFeeRate" => "0.00000",
        //                 "takerFeeRate" => "0.00025",
        //                 "builderFeeRate" => "0.0001"
        //             }
        //         )
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        $result = array();
        for ($i = 0; $i < count($data); $i++) {
            $fee = $this->safe_dict($data, $i, array());
            $parsed = $this->parse_trading_fee($fee);
            $symbol = $this->safe_string($parsed, 'symbol');
            $result[$symbol] = $parsed;
        }
        return $result;
    }

    public function parse_trading_fee($fee, $market = null): array {
        //
