        $marketId = $this->safe_string($fee, 'market');
        $market = $this->safe_market($marketId, $market);
        return array(
            'info' => $fee,
            'symbol' => $market['symbol'],
            'maker' => $this->safe_number($fee, 'makerFeeRate'),
