        $this->load_markets();
        $market = $this->market($symbol);
        $request = array(
            'market' => $market['id'],
            'leverage' => $this->number_to_string($leverage),
        );
        $response = $this->v1PrivatePatchUserLeverage ($this->extend($request, $params));
        //
        //     {
        //         "status" => "OK",
