    public function fetch_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetches information on multiple $orders made by the user
         *
         * @see https://api.docs.extended.exchange/#get-$orders-history
         *
         * @param {string} [$symbol] unified $market $symbol of the $orders
         * @param {int} [$since] the earliest time in ms to fetch $orders for
         * @param {int} [$limit] the maximum number of order structures to retrieve
         * @param {array} [$params] extra parameters specific to the exchange API endpoint
         * @param {boolean} [$params->paginate] default false, when true will automatically $paginate by calling this endpoint multiple times. See in the docs all the [available parameters](https://github.com/ccxt/ccxt/wiki/Manual#$pagination-$params)
         * @return {Order[]} a list of ~@link https://docs.ccxt.com/?id=order-structure order structures~
         */
        $this->load_markets();
        $paginate = false;
        list($paginate, $params) = $this->handle_option_and_params($params, 'fetchOrders', 'paginate');
        if ($paginate) {
            return $this->fetch_paginated_call_cursor('fetchOrders', $symbol, $since, $limit, $params, 'cursor', 'cursor', null, 100);
        }
        $market = null;
        $request = array();
        if ($symbol !== null) {
            $market = $this->market($symbol);
            $request['market'] = $market['id'];
        }
        if ($limit !== null) {
            $request['limit'] = $limit;
        }
        $response = $this->v1PrivateGetUserOrdersHistory ($this->extend($params, $request));
        //
        //     {
        //       "status" => "OK",
        //       "data" => array(
        //         {
        //           "id" => 1784963886257016832,
        //           "externalId" => "ExtId-1",
        //           "accountId" => 1,
        //           "market" => "BTC-USD",
        //           "status" => "FILLED",
        //           "type" => "LIMIT",
        //           "side" => "BUY",
        //           "price" => "39000",
        //           "averagePrice" => "39000",
        //           "qty" => "0.2",
        //           "filledQty" => "0.1",
        //           "payedFee" => "0.0120000000000000",
        //           "reduceOnly" => false,
        //           "postOnly" => false,
        //           "createdTime" => 1701563440000,
        //           "updatedTime" => 1701563440000,
        //           "timeInForce" => "IOC",
        //           "expireTime" => 1706563440
        //         }
        //       ),
        //       "pagination" => {
        //         "cursor" => 1784963886257016832,
        //         "count" => 1
        //       }
        //     }
        //
        $data = $this->safe_list($response, 'data', array());
        $pagination = $this->safe_dict($response, 'pagination', array());
        $cursor = $this->safe_string($pagination, 'cursor');
        $result = array();
        $dataLength = count($data);
        for ($i = 0; $i < $dataLength; $i++) {
            $entry = $data[$i];
            if (($cursor !== null) && ($i === $dataLength - 1)) {
                $entry = $this->extend($entry, array( 'cursor' => $cursor ));
            }
            $result[] = $entry;
        }
        $orders = $this->parse_orders($result, $market, $since, $limit);
        return $this->filter_by_symbol_since_limit($orders, $symbol, $since, $limit);
    }

    public function fetch_closed_orders(?string $symbol = null, ?int $since = null, ?int $limit = null, $params = array ()): array {
        /**
         * fetches information on multiple closed $orders made by the user
         *
